def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        complexity = 1.0
        offset = 0.0
        attenuator = 1.0
        flag = False
        for j in range(1, 15):
            if j % 2 == 0:
                complexity *= 1.03 + 0.007 * j
            elif j % 4 == 0:
                complexity *= 0.97 - 0.004 * j
            val_exp = np.exp(-abs(ratio - 0.15 * j))
            val_log = np.log1p((j + cap) * 0.05)
            if ratio < 0.12 * j:
                base_score += (j ** 3) * val_exp / (1 + ratio * j) * complexity
            else:
                base_score += (val_log + ratio ** 4) * complexity / (j + 3)
            if (cap * j + j*j) % 9 == 0:
                base_score *= 1.03
            elif (cap + item * j) % 8 == 0:
                base_score *= 0.95
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            offset += np.cbrt(diff) / (k + 4)
                        else:
                            offset -= np.log1p(abs(diff)) ** 0.9 / (k + 3)
                    else:
                        offset -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.8 and j % 3 == 0:
                attenuator *= 1.08 + 0.015 * j
                if j == 12:
                    flag = True
            elif ratio < 0.15 and j % 5 == 0:
                attenuator *= 0.85 - 0.012 * j
            if j % 6 == 1 and cap % (j+2) == 0:
                offset += np.cos(j * ratio) * 0.7
        base_score += offset * 0.9
        base_score *= attenuator
        if base_score <= 0:
            priorities[i] = -base_score * (np.log1p(cap + item) + np.sqrt(cap) * 1.1)
        else:
            if cap > item * 5:
                priorities[i] = -base_score / (np.sqrt(cap) + 0.5) * (1 + ratio) * (1.03 if flag else 1.0)
            else:
                priorities[i] = -base_score / (cap + 4) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.2 if cap % 3 == 0 else 1.1
        elif ratio < 0.03:
            priorities[i] *= 0.7 if cap % 4 == 0 else 0.8
        if cap % 2 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.05
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
